from pathlib import Path
import base64, zlib

path = Path("ErdosProblems/Erdos23GapGBTwoDefectFinal.lean")
text = path.read_text()
anchor = """#print axioms activeLevelSet_high_card_le_two
#print axioms IsGeodesic.levelAligned_of_twoSidedAnchors
#print axioms IsGeodesic.pair_spanTwo_geometry

end Erdos23GapGBTwoDefectFinal
"""
segment = zlib.decompress(base64.b64decode("")).decode()
replacement = segment + """
#print axioms activeLevelSet_high_card_le_two
#print axioms IsGeodesic.levelAligned_of_twoSidedAnchors
#print axioms IsGeodesic.pair_spanTwo_geometry
#print axioms totalCost_le_rlBudget_of_pureOverlap_allNonbridge_sameSide

end Erdos23GapGBTwoDefectFinal
"""
if "theorem totalCost_le_rlBudget_of_pureOverlap_allNonbridge_sameSide" in text:
    raise SystemExit(0)
if anchor not in text:
    raise SystemExit("expected module tail not found")
path.write_text(text.replace(anchor, replacement, 1))
